BEGIN;

-- 1. CREACIÓN DE TABLAS

CREATE TABLE Asset ( id VARCHAR(50) PRIMARY KEY, name VARCHAR(255) NOT NULL, category VARCHAR(50) NOT NULL, color VARCHAR(20), is_archived BOOLEAN DEFAULT false, risk_level VARCHAR(50), isin VARCHAR(50), ticker VARCHAR(50), description TEXT );

CREATE TABLE Asset_History ( id VARCHAR(100) PRIMARY KEY, asset_id VARCHAR(50) REFERENCES Asset(id), snapshot_date DATE NOT NULL, nav NUMERIC(15, 4), contribution NUMERIC(15, 4), participations NUMERIC(18, 8), liquid_nav_value NUMERIC(15, 4), mean_cost NUMERIC(15, 4) );

CREATE TABLE Transaction ( id VARCHAR(100) PRIMARY KEY, asset_id VARCHAR(50) REFERENCES Asset(id), transaction_date DATE NOT NULL, type VARCHAR(20), ticker VARCHAR(50), quantity NUMERIC(18, 8), price_per_unit NUMERIC(18, 8), fees NUMERIC(10, 4), total_amount NUMERIC(15, 4) );

